import{_ as t,o as a,c as s,ag as e}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Kupiki Hotspot Script","description":"Automated captive-portal WiFi hotspot on Raspberry Pi (CoovaChilli + FreeRADIUS).","frontmatter":{"title":"Kupiki Hotspot Script","description":"Automated captive-portal WiFi hotspot on Raspberry Pi (CoovaChilli + FreeRADIUS)."},"headers":[],"relativePath":"microcontrollers-and-socs/raspberry-pi/raspberry-pi-hotspot/kupiki-hotspot-script.md","filePath":"microcontrollers-and-socs/raspberry-pi/raspberry-pi-hotspot/kupiki-hotspot-script.md"}'),r={name:"microcontrollers-and-socs/raspberry-pi/raspberry-pi-hotspot/kupiki-hotspot-script.md"};function o(p,i,l,h,n,d){return a(),s("div",null,[...i[0]||(i[0]=[e(`<h1 id="kupiki-hotspot-script" tabindex="-1">Kupiki Hotspot Script <a class="header-anchor" href="#kupiki-hotspot-script" aria-label="Permalink to &quot;Kupiki Hotspot Script&quot;">​</a></h1><p>One-shot installer that turns a Raspberry Pi into a captive-portal WiFi hotspot with RADIUS authentication and daloRadius management UI.</p><h2 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h2><ul><li><a href="https://github.com/pihomeserver/Kupiki-Hotspot-Script" target="_blank" rel="noreferrer">pihomeserver/Kupiki-Hotspot-Script</a></li><li><a href="https://github.com/pihomeserver/Kupiki-Hotspot-Script/wiki" target="_blank" rel="noreferrer">Parameter wiki</a></li><li><a href="http://www.pihomeserver.fr/2015/08/05/raspberry-pi-coovachilli-et-freeradius-pour-un-hotspot-wifi-avec-portail-captif/" target="_blank" rel="noreferrer">Original blog tutorial</a> (archived)</li></ul><h2 id="what-you-get" tabindex="-1">What you get <a class="header-anchor" href="#what-you-get" aria-label="Permalink to &quot;What you get&quot;">​</a></h2><ul><li>Onboard WiFi as hotspot</li><li><strong>CoovaChilli</strong> captive portal (Nginx-served, HTML/JS customizable)</li><li>Optional user registration (config-gated)</li><li><strong>FreeRADIUS</strong> auth (user/password; optional MAC auth)</li><li><strong>daloRadius</strong> admin UI at <code>http://&lt;pi_ip&gt;/daloradius</code></li></ul><p>Designed with French public WiFi logging requirements in mind (see repo for legal/compliance notes).</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li>Raspberry Pi 3 or 3B+ (Pi 4 not verified at doc time)</li><li>Ethernet uplink, 4 GB+ SD card, Raspbian-like OS 9+</li></ul><h2 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/pihomeserver/Kupiki-Hotspot-Script.git</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Edit script header for your network settings (see wiki)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +x</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pihotspot.sh</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./pihotspot.sh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/pihotspot.log</span></span></code></pre></div><blockquote><p>Do not open daloRadius through the hotspot SSID — use Ethernet/LAN.</p></blockquote><h2 id="updates-v2-0-0" tabindex="-1">Updates (v2.0.0+) <a class="header-anchor" href="#updates-v2-0-0" aria-label="Permalink to &quot;Updates (v2.0.0+)&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/kupiki/kupiki_updater.sh</span></span></code></pre></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./hotspotos.html">HotSpotOS</a></li><li><a href="./rpi-wireless-hotspot.html">RPI Wireless Hotspot</a></li></ul>`,16)])])}const k=t(r,[["render",o]]);export{u as __pageData,k as default};
